/** App Store metadata field specifications: labels, limits, editing surface. */

export type InfoField = 'name' | 'subtitle' | 'privacyPolicyUrl' | 'privacyChoicesUrl';
export type VersionField =
  | 'description'
  | 'keywords'
  | 'promotionalText'
  | 'whatsNew'
  | 'supportUrl'
  | 'marketingUrl';

export type MetadataField = InfoField | VersionField;

export interface FieldSpec {
  field: MetadataField;
  target: 'info' | 'version';
  label: string;
  maxLength: number;
  multiline: boolean;
  kind: 'text' | 'keywords' | 'url';
  help?: string;
  /** Field may be translated/generated by AI. URLs are excluded. */
  aiEligible: boolean;
}

