export const INFO_FIELDS: InfoField[] = ['name', 'subtitle', 'privacyPolicyUrl', 'privacyChoicesUrl'];
export const VERSION_FIELDS: VersionField[] = [
  'promotionalText',
  'description',
  'keywords',
  'whatsNew',
  'supportUrl',
  'marketingUrl',
];
export const ALL_FIELDS: MetadataField[] = [...INFO_FIELDS, ...VERSION_FIELDS];

export function validateFieldValue(field: MetadataField, value: string): string | null {
  const spec = FIELD_SPECS[field];
  if (value.length > spec.maxLength) {
    return `${spec.label} exceeds ${spec.maxLength} characters (currently ${value.length}).`;
  }
  if (spec.kind === 'url' && value.trim() !== '') {
    // Keep shared/ free of DOM/Node lib types — a light check is enough; Apple validates authoritatively.
    if (!/^https?:\/\/[^\s]+\.[^\s]{2,}/i.test(value.trim())) {
      return 'Must be a valid http(s) URL.';
    }
  }
  return null;
}
